type Role string

const (
    RoleUser  Role = "user"
    RoleMod   Role = "moderator"
    RoleAdmin Role = "admin"
)

type User struct {
    ID       string
    Username string
    Role     Role
    Conn     *websocket.Conn
    mu       sync.Mutex
}

type Session struct {
    UserID    string
    Token     string
    Role      Role
    ExpiresAt time.Time
}

type AuthService struct {
    sessions map[string]*Session
    mu       sync.RWMutex
}

func NewAuthService() *AuthService {
    return &AuthService{
        sessions: make(map[string]*Session),
    }
}

func (a *AuthService) CreateSession(userID string, role Role) (string, error) {
    tokenBytes := make([]byte, 32)
    if _, err := rand.Read(tokenBytes); err != nil {
        return "", err
    }
    token := base64.URLEncoding.EncodeToString(tokenBytes)

    hash := sha256.Sum256([]byte(token))
    tokenHash := base64.URLEncoding.EncodeToString(hash[:])

    a.mu.Lock()
    defer a.mu.Unlock()

    a.sessions[tokenHash] = &Session{
        UserID:    userID,
        Token:     tokenHash,
        Role:      role,
        ExpiresAt: time.Now().Add(24 * time.Hour),
    }

    return token, nil
}

func (a *AuthService) ValidateSession(token string) (*Session, bool) {
    hash := sha256.Sum256([]byte(token))
    tokenHash := base64.URLEncoding.EncodeToString(hash[:])

    a.mu.RLock()
    defer a.mu.RUnlock()

    session, exists := a.sessions[tokenHash]
    if !exists || time.Now().After(session.ExpiresAt) {
        return nil, false
    }

    return session, true
}

func (a *AuthService) RevokeSession(token string) {
    hash := sha256.Sum256([]byte(token))
    tokenHash := base64.URLEncoding.EncodeToString(hash[:])

    a.mu.Lock()
    defer a.mu.Unlock()
    delete(a.sessions, tokenHash)
}

